nodes.notes:
Seerr - search and request movies and TV shows for your media library.

Actions:
  search - search for movies or TV shows by title. Use for "search for Inception", "find Breaking Bad".
  request - request a movie or TV show for download. Requires media_id and media_type from a prior search. For TV, optionally specify seasons.
  my_requests - check status of your media requests. Use for "what have I requested", "my requests".
  trending - see what's trending. Use for "what's trending", "popular movies", "trending TV shows".
  upcoming - see upcoming movie releases. Use for "what movies are coming out", "upcoming releases".
  details - get full details on a movie or TV show. Requires media_id and media_type from a prior search.
  cancel_request - cancel a pending request. Requires request_id from my_requests.

Rules:
- media_id and media_type come from search results. Never fabricate IDs.
- media_type is either "movie" or "tv".
- request_id comes from my_requests. Never fabricate request IDs.
- Always search first before requesting.

Chaining:
- "Download Inception" -> search "inception" -> request with media_id and media_type from results
- "What's trending on TV?" -> trending with media_type "tv"
- "Cancel my last request" -> my_requests -> cancel_request with request_id

---schema
{
  "action": {
    "type": "string",
    "description": "One of: search, request, my_requests, trending, upcoming, details, cancel_request",
    "required": true
  },
  "query": {
    "type": "string",
    "description": "Search term, e.g. Inception, Breaking Bad. For: search"
  },
  "media_id": {
    "type": "integer",
    "description": "TMDB media ID from search results. For: request, details"
  },
  "media_type": {
    "type": "string",
    "description": "One of: movie, tv. For: request, details, trending (optional filter)"
  },
  "request_id": {
    "type": "integer",
    "description": "Request ID from my_requests. For: cancel_request"
  },
  "filter": {
    "type": "string",
    "description": "Filter requests. One of: all, pending, approved, available, declined. For: my_requests"
  },
  "seasons": {
    "type": "array|string",
    "description": "Season numbers to request, e.g. [1, 2] or 'all'. Omit for all seasons. For: request (TV only)"
  }
}

parameters.jsCode:
let data;
const input = $input.item.json;

if (typeof input.body === 'string') {
  data = JSON.parse(input.body);
} else if (typeof input.body === 'object') {
  data = input.body;
} else {
  data = input;
}

const action = (data.action || '').toLowerCase().trim();

if (!action) {
  return [{ json: { error: true, message: 'Action is required. Use one of: search, request, my_requests, trending, upcoming, details, cancel_request.' } }];
}

const validActions = ['search', 'request', 'my_requests', 'trending', 'upcoming', 'details', 'cancel_request'];
if (!validActions.includes(action)) {
  return [{ json: { error: true, message: `Unknown action: ${action}. Use one of: search, request, my_requests, trending, upcoming, details, cancel_request.` } }];
}

const query = data.query || '';
const media_id = parseInt(data.media_id) || null;
const media_type = (data.media_type || '').toLowerCase().trim();
const request_id = parseInt(data.request_id) || null;
const filter = (data.filter || '').toLowerCase().trim();

// Parse seasons: accept array of numbers, single number, or "all"
let seasons = data.seasons || null;
if (seasons !== null && seasons !== 'all') {
  if (Array.isArray(seasons)) {
    seasons = seasons.map(s => parseInt(s)).filter(s => !isNaN(s));
  } else {
    const parsed = parseInt(seasons);
    seasons = isNaN(parsed) ? null : [parsed];
  }
}

if (action === 'cancel_request' && !request_id) {
  return [{ json: { error: true, message: 'request_id is required for cancel_request. Check my_requests first.' } }];
}

return [{ json: { action, query, media_id, media_type, request_id, filter, seasons } }];

const response = $input.item.json;
const results = response.results || [];
const mediaTypeFilter = $('Parse Parameters').item.json.media_type;

let filtered = results.filter(r => r.mediaType === 'movie' || r.mediaType === 'tv');
if (mediaTypeFilter) {
  filtered = filtered.filter(r => r.mediaType === mediaTypeFilter);
}

if (filtered.length === 0) {
  return [{ json: { message: 'No results found.', results: [] } }];
}

const limited = filtered.slice(0, 10);
const formatted = limited.map((r, idx) => {
  const title = r.title || r.name || 'Unknown';
  const year = (r.releaseDate || r.firstAirDate || '').substring(0, 4);
  const type = r.mediaType === 'movie' ? 'Movie' : 'TV Show';
  const status = r.mediaInfo ? (r.mediaInfo.status === 5 ? 'Available' : r.mediaInfo.status === 3 ? 'Requested' : 'Not Available') : 'Not Requested';
  return {
    number: idx + 1,
    media_id: r.id,
    title: title,
    year: year,
    media_type: r.mediaType,
    status: status,
    overview: (r.overview || '').substring(0, 100)
  };
});

let message = `Found ${filtered.length} result${filtered.length === 1 ? '' : 's'}. `;
formatted.forEach(r => {
  message += `${r.number}. ${r.title}`;
  if (r.year) message += ` (${r.year})`;
  message += ` - ${r.media_type === 'movie' ? 'Movie' : 'TV Show'} - ${r.status}. `;
});

return [{ json: { message: message.trim(), count: filtered.length, results: formatted } }];

const data = $input.item.json;
if (!data.media_id) {
  return [{ json: { error: true, message: 'media_id is required for request. Search first to find the media ID.' } }];
}
if (!data.media_type || !['movie', 'tv'].includes(data.media_type)) {
  return [{ json: { error: true, message: 'media_type is required for request. Must be "movie" or "tv".' } }];
}
return [{ json: data }];

