parameters.jsCode:
const result = $input.item.json;
const params = $('Parse Parameters').item.json;
const mediaType = params.media_type === 'movie' ? 'Movie' : 'TV show';
const seasons = params.seasons;
let message = `${mediaType} has been requested.`;
if (seasons && seasons !== 'all' && Array.isArray(seasons)) {
  message = `${mediaType} season${seasons.length > 1 ? 's' : ''} ${seasons.join(', ')} ha${seasons.length > 1 ? 've' : 's'} been requested.`;
}
message += ' It will be processed shortly.';
return [{ json: { message, success: true, request_id: result.id } }];

const response = $input.item.json;
const results = response.results || [];

if (results.length === 0) {
  return [{ json: { message: 'You have no requests.', count: 0, requests: [] } }];
}

function titleFromSlug(slug) {
  if (!slug) return null;
  const cleaned = slug.replace(/-\d{4}$/, '');
  return cleaned.split('-').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
}

const formatted = results.map((r, idx) => {
  const media = r.media || {};
  const slug = media.externalServiceSlug || media.externalServiceSlug4k || '';
  const title = titleFromSlug(slug) || null;
  const type = r.type === 'movie' ? 'Movie' : 'TV Show';
  const statusMap = { 1: 'Pending', 2: 'Approved', 3: 'Declined' };
  const mediaStatusMap = { 1: 'Unknown', 2: 'Pending', 3: 'Processing', 4: 'Partially Available', 5: 'Available' };
  const reqStatus = statusMap[r.status] || 'Unknown';
  const availability = mediaStatusMap[media.status] || 'Unknown';
  return {
    number: idx + 1,
    request_id: r.id,
    title: title,
    type: type,
    request_status: reqStatus,
    availability: availability,
    media_id: media.tmdbId,
    media_type: r.type
  };
});

let message = `You have ${results.length} request${results.length === 1 ? '' : 's'}. `;
formatted.forEach(r => {
  message += `${r.number}. `;
  if (r.title) {
    message += `${r.title} - ${r.type}`;
  } else {
    message += `${r.type} (ID: ${r.media_id})`;
  }
  message += ` - ${r.request_status}`;
  if (r.availability === 'Available') message += ' (Available)';
  else if (r.availability === 'Partially Available') message += ' (Partially Available)';
  message += '. ';
});

message += 'Use details with media_id and media_type to get the title of any item.';

return [{ json: { message: message.trim(), count: results.length, requests: formatted } }];

const data = $input.item.json;
const mediaType = data.media_type;
let url;
if (mediaType === 'movie') {
  url = '${SEERR_URL}/api/v1/discover/movies';
} else if (mediaType === 'tv') {
  url = '${SEERR_URL}/api/v1/discover/tv';
} else {
  url = '${SEERR_URL}/api/v1/discover/trending';
}
return [{ json: { url, media_type: mediaType } }];

const response = $input.item.json;
const results = response.results || [];

if (results.length === 0) {
  return [{ json: { message: 'Nothing trending right now.', results: [] } }];
}

const limited = results.slice(0, 10);
const formatted = limited.map((r, idx) => {
  const title = r.title || r.name || 'Unknown';
  const year = (r.releaseDate || r.firstAirDate || '').substring(0, 4);
  const type = r.mediaType === 'movie' ? 'Movie' : 'TV Show';
  return {
    number: idx + 1,
    media_id: r.id,
    title: title,
    year: year,
    media_type: r.mediaType,
    overview: (r.overview || '').substring(0, 100)
  };
});

let message = 'Trending now: ';
formatted.forEach(r => {
  message += `${r.number}. ${r.title}`;
  if (r.year) message += ` (${r.year})`;
  message += ` - ${r.media_type === 'movie' ? 'Movie' : 'TV Show'}. `;
});

return [{ json: { message: message.trim(), count: results.length, results: formatted } }];

const response = $input.item.json;
const results = response.results || [];

if (results.length === 0) {
  return [{ json: { message: 'No upcoming movies found.', results: [] } }];
}

const limited = results.slice(0, 10);
const formatted = limited.map((r, idx) => ({
  number: idx + 1,
  media_id: r.id,
  title: r.title || 'Unknown',
  release_date: r.releaseDate || 'TBD',
  overview: (r.overview || '').substring(0, 100)
}));

let message = 'Upcoming movies: ';
formatted.forEach(r => {
  message += `${r.number}. ${r.title} - ${r.release_date}. `;
});

return [{ json: { message: message.trim(), count: results.length, results: formatted } }];

const data = $input.item.json;
if (!data.media_id) {
  return [{ json: { error: true, message: 'media_id is required for details. Search first.' } }];
}
if (!data.media_type || !['movie', 'tv'].includes(data.media_type)) {
  return [{ json: { error: true, message: 'media_type is required for details. Must be "movie" or "tv".' } }];
}
const url = data.media_type === 'movie'
  ? '${SEERR_URL}/api/v1/movie/' + data.media_id
  : '${SEERR_URL}/api/v1/tv/' + data.media_id;
return [{ json: { url, media_id: data.media_id, media_type: data.media_type } }];

const r = $input.item.json;
const mediaType = $('Build Details URL').item.json.media_type;

const title = r.title || r.name || 'Unknown';
const year = (r.releaseDate || r.firstAirDate || '').substring(0, 4);
const rating = r.voteAverage ? r.voteAverage.toFixed(1) + '/10' : 'N/A';
const genres = (r.genres || []).map(g => g.name).join(', ') || 'N/A';
const overview = r.overview || 'No overview available.';

let details = `${title}`;
if (year) details += ` (${year})`;
details += `. Rating: ${rating}. Genres: ${genres}.`;

if (mediaType === 'movie') {
  const runtime = r.runtime ? `${r.runtime} minutes` : 'N/A';
  details += ` Runtime: ${runtime}.`;
} else {
  const seasons = r.numberOfSeasons || 'N/A';
  const episodes = r.numberOfEpisodes || 'N/A';
  details += ` ${seasons} season${seasons !== 1 ? 's' : ''}, ${episodes} episodes.`;
  const status = r.status || 'Unknown';
  details += ` Status: ${status}.`;
}

details += ` ${overview}`;

const mediaInfo = r.mediaInfo;
let availability = 'Not requested';
if (mediaInfo) {
  if (mediaInfo.status === 5) availability = 'Available';
  else if (mediaInfo.status === 4) availability = 'Processing';
  else if (mediaInfo.status === 3) availability = 'Requested';
}
details += ` Availability: ${availability}.`;

return [{ json: { message: details, media_id: r.id, media_type: mediaType, title, year } }];

const errorData = $input.item.json;

if (errorData.error === true && errorData.message) {
  return [{ json: { message: errorData.message, error: true } }];
}

let errorMsg = errorData.message || errorData.error || 'Unknown error';
if (typeof errorMsg === 'object') {
  errorMsg = errorMsg.message || JSON.stringify(errorMsg);
}

if (errorMsg.includes('401') || errorMsg.includes('Unauthorized')) {
  errorMsg = 'Seerr authentication failed. Check your API key.';
} else if (errorMsg.includes('404') || errorMsg.includes('Not Found')) {
  errorMsg = 'Not found. The media or request ID may be invalid.';
} else if (errorMsg.includes('409')) {
  errorMsg = 'This media has already been requested.';
} else if (errorMsg.includes('ECONNREFUSED')) {
  errorMsg = 'Cannot connect to Seerr. Check the URL and make sure Seerr is running.';
}

return [{ json: { message: 'Seerr error: ' + errorMsg, error: true } }];
